import{ChromeFreeAIProvider as a}from"../../providers/chrome-free-ai-provider.js";export function registerChromeFreeAIHandlers(s,{log:t}){s.set("GET_AI_STATUS",async(o,d,r)=>{try{const e=await a.getStatus();t.info(`AI status request: ${e}`),r({status:e})}catch(e){t.error("GET_AI_STATUS failed:",e.message),r({status:a.STATUS.UNAVAILABLE})}return!0}),s.set("TRIGGER_MODEL_DOWNLOAD",async(o,d,r)=>{t.info("Model download triggered by popup");try{await a.ensureModel(),r({triggered:!0})}catch(e){t.error("Model download failed:",e.message),r({triggered:!1,error:e.message})}return!0})}
